import { mkdir, readFile, writeFile } from "node:fs/promises";
import { homedir } from "node:os";
import { dirname, join, resolve } from "node:path";

const CONFIG_DIRECTORY_NAME = ".building-agent";
const CONFIG_FILE_NAME = "config.json";

export interface CliConfig {
  apiUrl?: string;
  token?: string;
  selectedProjectId?: string;
}

export interface ConfigStoreOptions {
  homeDir?: string;
  env?: NodeJS.ProcessEnv;
}

export interface ConfigDiagnostics {
  cliHomeDir: string;
  configPath: string;
}

export class CliConfigError extends Error {
  readonly code: "config_parse_failed" | "config_read_failed" | "config_write_failed";
  readonly diagnostics: ConfigDiagnostics;

  constructor(
    code: CliConfigError["code"],
    message: string,
    diagnostics: ConfigDiagnostics,
    cause?: unknown
  ) {
    super(message, { cause });
    this.name = "CliConfigError";
    this.code = code;
    this.diagnostics = diagnostics;
  }

  toJSON(): { error: { code: string; message: string; cliHomeDir: string; configPath: string } } {
    return {
      error: {
        code: this.code,
        message: this.message,
        cliHomeDir: this.diagnostics.cliHomeDir,
        configPath: this.diagnostics.configPath
      }
    };
  }
}

function configuredHomeDir(options: ConfigStoreOptions = {}): string {
  const env = options.env ?? process.env;
  return options.homeDir ?? env.BUILDING_AGENT_CLI_HOME ?? homedir();
}

export function getConfigDiagnostics(options: ConfigStoreOptions = {}): ConfigDiagnostics {
  const cliHomeDir = resolve(configuredHomeDir(options));
  return {
    cliHomeDir,
    configPath: join(cliHomeDir, CONFIG_DIRECTORY_NAME, CONFIG_FILE_NAME)
  };
}

function assertPlainConfig(value: unknown, diagnostics: ConfigDiagnostics): CliConfig {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    throw new CliConfigError("config_parse_failed", "CLI config file must contain a JSON object.", diagnostics);
  }

  const candidate = value as Record<string, unknown>;
  for (const key of ["apiUrl", "token", "selectedProjectId"] as const) {
    if (candidate[key] !== undefined && typeof candidate[key] !== "string") {
      throw new CliConfigError("config_parse_failed", `CLI config field ${key} must be a string.`, diagnostics);
    }
  }

  return {
    ...(typeof candidate.apiUrl === "string" ? { apiUrl: candidate.apiUrl } : {}),
    ...(typeof candidate.token === "string" ? { token: candidate.token } : {}),
    ...(typeof candidate.selectedProjectId === "string" ? { selectedProjectId: candidate.selectedProjectId } : {})
  };
}

export async function loadConfig(options: ConfigStoreOptions = {}): Promise<CliConfig> {
  const diagnostics = getConfigDiagnostics(options);

  try {
    const raw = await readFile(diagnostics.configPath, "utf8");
    return assertPlainConfig(JSON.parse(raw) as unknown, diagnostics);
  } catch (error) {
    if (error instanceof CliConfigError) {
      throw error;
    }

    if (error instanceof SyntaxError) {
      throw new CliConfigError("config_parse_failed", "CLI config file contains malformed JSON.", diagnostics, error);
    }

    if (typeof error === "object" && error !== null && "code" in error && error.code === "ENOENT") {
      return {};
    }

    throw new CliConfigError("config_read_failed", "Failed to read CLI config file.", diagnostics, error);
  }
}

export async function saveConfig(config: CliConfig, options: ConfigStoreOptions = {}): Promise<ConfigDiagnostics> {
  const diagnostics = getConfigDiagnostics(options);
  const safeConfig = assertPlainConfig(config, diagnostics);

  try {
    await mkdir(dirname(diagnostics.configPath), { recursive: true, mode: 0o700 });
    await writeFile(diagnostics.configPath, `${JSON.stringify(safeConfig, null, 2)}\n`, { mode: 0o600 });
    return diagnostics;
  } catch (error) {
    throw new CliConfigError("config_write_failed", "Failed to write CLI config file.", diagnostics, error);
  }
}

export function redactConfig(config: CliConfig): CliConfig {
  return {
    ...config,
    ...(config.token ? { token: "[redacted]" } : {})
  };
}

#!/usr/bin/env node
import { CliConfigError, getConfigDiagnostics, loadConfig, redactConfig } from "./config.js";

function printJson(value: unknown): void {
  process.stdout.write(`${JSON.stringify(value, null, 2)}\n`);
}

async function main(argv: string[]): Promise<number> {
  const [command] = argv;

  if (!command || command === "help" || command === "--help") {
    process.stdout.write("building-agent <session|config-path>\n");
    return 0;
  }

  if (command === "config-path") {
    printJson(getConfigDiagnostics());
    return 0;
  }

  if (command === "session") {
    const diagnostics = getConfigDiagnostics();
    const config = await loadConfig();
    printJson({ diagnostics, config: redactConfig(config) });
    return 0;
  }

  process.stderr.write(`Unknown command: ${command}\n`);
  return 2;
}

try {
  process.exitCode = await main(process.argv.slice(2));
} catch (error) {
  if (error instanceof CliConfigError) {
    process.stderr.write(`${JSON.stringify(error.toJSON())}\n`);
    process.exitCode = 1;
  } else {
    process.stderr.write(`${error instanceof Error ? error.message : "Unknown CLI error"}\n`);
    process.exitCode = 1;
  }
}

import Fastify, { type FastifyInstance, type FastifyReply } from "fastify";
import cors from "@fastify/cors";
import {
  authenticateRequest,
  getPermissionsForSelectedProject,
  requestIdFor,
  requirePermission,
  requireProjectMembership,
  requireSelectedProject,
  sendError
} from "./auth.js";
import { createSeedStore, type ChatMessage, type SeedStore } from "./seed.js";

interface BuildServerOptions {
  store?: SeedStore;
}

interface ProjectParams {
  projectId: string;
}

interface LoginBody {
  email?: unknown;
  password?: unknown;
}

interface ChatBody {
  message?: unknown;
}

let messageSequence = 0;

function nextMessageId(): string {
  messageSequence += 1;
  return `msg_${String(messageSequence).padStart(6, "0")}`;
}

function bounded<T>(items: T[], limit: number): T[] {
  return items.slice(0, limit);
}

function boundedPlaceholderList<T>(items: T[], store: SeedStore): T[] {
  return bounded(items, store.maxListSize);
}

function isReply(value: unknown): value is FastifyReply {
  return typeof value === "object" && value !== null && "sent" in value;
}

function validateChatMessage(body: unknown): string | null {
  if (typeof body !== "object" || body === null || Array.isArray(body)) {
    return null;
  }

  const message = (body as ChatBody).message;
  if (typeof message !== "string") {
    return null;
  }

  const trimmed = message.trim();
  if (trimmed.length === 0 || trimmed.length > 1000) {
    return null;
  }

  return trimmed;
}

export function buildServer(options: BuildServerOptions = {}): FastifyInstance {
  const store = options.store ?? createSeedStore();
  messageSequence = 0;

  const app = Fastify({
    logger: false,
    genReqId: (() => {
      let sequence = 0;
      return () => {
        sequence += 1;
        return `req_${String(sequence).padStart(6, "0")}`;
      };
    })()
  });

  void app.register(cors, { origin: true });

  app.get("/health", async (request) => ({
    ok: true,
    service: "building-agent-api",
    requestId: requestIdFor(request)
  }));

  app.post<{ Body: LoginBody }>("/api/login", async (request, reply) => {
    const { email, password } = request.body ?? {};
    if (typeof email !== "string" || typeof password !== "string" || !email.trim() || !password) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const user = store.users.find((candidate) => candidate.email === email && candidate.password === password);
    if (!user) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const token = Object.entries(store.tokens).find(([, userId]) => userId === user.id)?.[0];
    if (!token) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    store.sessionsByToken[token] = store.sessionsByToken[token] ?? { userId: user.id, selectedProjectId: null };

    return {
      token,
      user: { id: user.id, name: user.name },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/session", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    return {
      session: {
        userId: session.userId,
        projectId: session.projectId,
        permissions: session.permissions
      },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/projects", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const memberships = store.memberships.filter((membership) => membership.userId === session.userId);
    const projects = bounded(memberships, store.maxListSize).flatMap((membership) => {
      const project = store.projects.find((candidate) => candidate.id === membership.projectId);
      return project ? [{ id: project.id, name: project.name, permissions: membership.permissions }] : [];
    });

    return { projects, limit: store.maxListSize, requestId: requestIdFor(request) };
  });

  app.get("/api/registry", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    return {
      runtimeProviders: boundedPlaceholderList(store.runtimeProviders, store),
      tools: boundedPlaceholderList(store.tools, store),
      skills: boundedPlaceholderList(store.skills, store),
      gateways: boundedPlaceholderList(store.gateways, store),
      buildingCapabilities: boundedPlaceholderList(store.buildingCapabilities, store),
      limit: store.maxListSize,
      placeholderOnly: true,
      requestId: requestIdFor(request)
    };
  });

  app.get<{ Params: ProjectParams }>("/api/projects/:projectId/management", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const readable = requirePermission(request, reply, membership, "chat:read");
    if (isReply(readable)) {
      return readable;
    }

    const management = store.managementByProject[request.params.projectId] ?? {
      gateways: [],
      capabilities: [],
      tools: []
    };

    return {
      projectId: request.params.projectId,
      gateways: boundedPlaceholderList(management.gateways, store),
      capabilities: boundedPlaceholderList(management.capabilities, store),
      tools: boundedPlaceholderList(management.tools, store),
      limit: store.maxListSize,
      placeholderOnly: true,
      requestId: requestIdFor(request)
    };
  });

  app.post<{ Params: ProjectParams }>("/api/projects/:projectId/select", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selectedSession = {
      userId: session.userId,
      selectedProjectId: request.params.projectId
    };
    store.sessionsByToken[session.token] = selectedSession;

    return {
      session: {
        userId: session.userId,
        projectId: request.params.projectId,
        permissions: getPermissionsForSelectedProject(store, selectedSession)
      },
      requestId: requestIdFor(request)
    };
  });

  app.get<{ Params: ProjectParams }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const readable = requirePermission(request, reply, membership, "chat:read");
    if (isReply(readable)) {
      return readable;
    }

    return {
      messages: bounded(store.messagesByProject[request.params.projectId] ?? [], store.maxListSize),
      limit: store.maxListSize,
      requestId: requestIdFor(request)
    };
  });

  app.post<{ Params: ProjectParams; Body: ChatBody }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {

